/***********************************************************************************
  Implementing Breadth first search on OpenMP using algorithm given in HiPC'07
  paper "Accelerating Large Graph Algorithms on the GPU using CUDA"

  Translated from CUDA to OpenMP
 ************************************************************************************/
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define MAX_THREADS_PER_BLOCK 512

int no_of_nodes;
int edge_list_size;
FILE *fp;

//Structure to hold a node information
struct Node
{
    int starting;
    int no_of_edges;
};

void BFSGraph(int argc, char** argv);

////////////////////////////////////////////////////////////////////////////////
// Main Program
////////////////////////////////////////////////////////////////////////////////
int main( int argc, char** argv) 
{
    no_of_nodes=0;
    edge_list_size=0;
    BFSGraph( argc, argv);
    return 0;
}

void Usage(int argc, char**argv){
    fprintf(stderr,"Usage: %s <input_file>\n", argv[0]);
}

// Kernel 1: Process frontier nodes
void Kernel(Node* h_graph_nodes, int* h_graph_edges, bool* h_graph_mask, 
            bool* h_updating_graph_mask, bool* h_graph_visited, int* h_cost, int no_of_nodes)
{
    #pragma omp parallel for schedule(static)
    for(int tid = 0; tid < no_of_nodes; tid++)
    {
        if(h_graph_mask[tid])
        {
            h_graph_mask[tid] = false;
            for(int i = h_graph_nodes[tid].starting; 
                i < (h_graph_nodes[tid].no_of_edges + h_graph_nodes[tid].starting); i++)
            {
                int id = h_graph_edges[i];
                if(!h_graph_visited[id])
                {
                    h_cost[id] = h_cost[tid] + 1;
                    h_updating_graph_mask[id] = true;
                }
            }
        }
    }
}

// Kernel 2: Update visited and frontier
void Kernel2(bool* h_graph_mask, bool* h_updating_graph_mask, bool* h_graph_visited, 
             bool* over, int no_of_nodes)
{
    #pragma omp parallel for schedule(static)
    for(int tid = 0; tid < no_of_nodes; tid++)
    {
        if(h_updating_graph_mask[tid])
        {
            h_graph_mask[tid] = true;
            h_graph_visited[tid] = true;
            #pragma omp critical
            {
                *over = true;
            }
            h_updating_graph_mask[tid] = false;
        }
    }
}

////////////////////////////////////////////////////////////////////////////////
//Apply BFS on a Graph using OpenMP
////////////////////////////////////////////////////////////////////////////////
void BFSGraph( int argc, char** argv) 
{
    char *input_f;
    if(2 != argc){
        Usage(argc, argv);
        exit(0);
    }

    input_f = argv[1];
    printf("Reading File\n");
    fflush(stdout);
    //Read in Graph from a file
    fp = fopen(input_f,"r");
    if(!fp)
    {
        printf("Error Reading graph file\n");
        fflush(stdout);
        return;
    }

    int source = 0;

    fscanf(fp,"%d",&no_of_nodes);

    // allocate host memory
    Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
    bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
    bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
    bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

    int start, edgeno;   
    // initalize the memory
    for( unsigned int i = 0; (int)i < no_of_nodes; i++) 
    {
        fscanf(fp,"%d %d",&start,&edgeno);
        h_graph_nodes[i].starting = start;
        h_graph_nodes[i].no_of_edges = edgeno;
        h_graph_mask[i]=false;
        h_updating_graph_mask[i]=false;
        h_graph_visited[i]=false;
    }

    //read the source node from the file
    fscanf(fp,"%d",&source);
    source=0;

    //set the source node as true in the mask
    h_graph_mask[source]=true;
    h_graph_visited[source]=true;

    fscanf(fp,"%d",&edge_list_size);

    int id,cost;
    int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
    for(int i=0; edge_list_size > i ; i++)
    {
        fscanf(fp,"%d",&id);
        fscanf(fp,"%d",&cost);
        h_graph_edges[i] = id;
    }

    if(fp)
        fclose(fp);    

    printf("Read File\n");
    fflush(stdout);

    // allocate mem for the result on host side
    int* h_cost = (int*) malloc( sizeof(int)*no_of_nodes);
    for(int i=0;no_of_nodes > i;i++)
        h_cost[i]=-1;
    h_cost[source]=0;

    //make a bool to check if the execution is over
    bool stop;

    printf("Copied Everything to GPU memory\n");
    fflush(stdout);
    printf("Start traversing the tree\n");
    fflush(stdout);

    int k=0;
    //Call the Kernel until all the elements of Frontier are not false
    do
    {
        //if no thread changes this value then the loop stops
        stop=false;

        Kernel(h_graph_nodes, h_graph_edges, h_graph_mask, h_updating_graph_mask, 
               h_graph_visited, h_cost, no_of_nodes);

        Kernel2(h_graph_mask, h_updating_graph_mask, h_graph_visited, &stop, no_of_nodes);

        k++;
    }
    while(stop);

    printf("Kernel Executed %d times\n",k);
    fflush(stdout);

    //Store the result into a file
    FILE *fpo = fopen("result.txt","w");
    for(int i=0;no_of_nodes > i;i++)
        fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
    fclose(fpo);
    printf("Result stored in result.txt\n");
    fflush(stdout);

    // cleanup memory
    free( h_graph_nodes);
    free( h_graph_edges);
    free( h_graph_mask);
    free( h_updating_graph_mask);
    free( h_graph_visited);
    free( h_cost);
}
